"""
Git Version Control - Auto-track all code changes
Minimal wrapper, zero config
"""

import os
import subprocess
import json
from datetime import datetime

WORKSPACE = os.path.expanduser("~/workspace")

def run(cmd, cwd=None):
    """Run shell command, return (success, output)"""
    try:
        result = subprocess.run(
            cmd, shell=True, capture_output=True, text=True,
            cwd=cwd or WORKSPACE, timeout=30
        )
        return result.returncode == 0, result.stdout + result.stderr
    except Exception as e:
        return False, str(e)

class GitTracker:
    """Auto git tracking for workspace"""

    def __init__(self):
        self.workspace = WORKSPACE
        self._ensure_repo()

    def _ensure_repo(self):
        """Init git if not exists"""
        if not os.path.exists(os.path.join(self.workspace, ".git")):
            ok, out = run("git init")
            if ok:
                run('git config user.email "agent@termux.local"')
                run('git config user.name "Agent"')
                print(f"✅ Git repo initialized: {self.workspace}")
            else:
                print(f"❌ Git init failed: {out}")

    def status(self):
        """Git status summary"""
        ok, out = run("git status --short")
        files = [l.strip() for l in out.split('\n') if l.strip()]
        return {
            "changed": len(files),
            "files": files[:20],  # max 20
            "full": out
        }

    def snapshot(self, message=None):
        """Commit all changes"""
        message = message or f"snapshot_{datetime.now().strftime('%Y%m%d_%H%M%S')}"
        run("git add -A")
        ok, out = run(f'git commit -m "{message}"')
        if ok:
            # Get commit hash
            _, hash_out = run("git rev-parse --short HEAD")
            return {
                "committed": ok,
                "hash": hash_out.strip(),
                "message": message
            }
        return {"committed": False, "error": out}

    def log(self, n=10):
        """Last n commits"""
        ok, out = run(f"git log --oneline -{n}")
        return out.strip().split('\n') if ok and out.strip() else []

    def diff(self):
        """Unstaged diff"""
        ok, out = run("git diff --stat")
        return out

    def undo(self, file_path):
        """Revert single file"""
        ok, out = run(f"git checkout -- {file_path}")
        return ok


# Self-test
if __name__ == "__main__":
    print("=== GIT TRACKER SELF-TEST ===\n")

    gt = GitTracker()

    # Status
    status = gt.status()
    print(f"📁 Files changed: {status['changed']}")
    if status['files']:
        for f in status['files'][:5]:
            print(f"  {f}")

    # Snapshot
    snap = gt.snapshot("Auto-snapshot from upgrade")
    if snap['committed']:
        print(f"\n✅ Snapshot: {snap['hash']} - {snap['message']}")

    # Log
    log = gt.log(5)
    print(f"\n📋 Recent commits: {len(log)}")
    for l in log:
        print(f"  {l}")

    print("\n🎉 GIT TRACKER READY!")
