public class MainActivity extends AppCompatActivity {

    private static final int PERMISSION_REQUEST_CODE = 100;
    private static final String SOVEREIGN_DIR = "/sdcard/sovereign";
    private static final String INPUT_FILE = SOVEREIGN_DIR + "/input.txt";
    private static final String OUTPUT_FILE = SOVEREIGN_DIR + "/output.txt";
    private static final String STATUS_FILE = SOVEREIGN_DIR + "/status.txt";
    private static final String HISTORY_FILE = SOVEREIGN_DIR + "/history.json";

    private TextView chatDisplay;
    private ScrollView scrollView;
    private EditText inputField;
    private Button sendButton;
    private TextView statusText;
    private Handler handler;
    private List<ChatMessage> chatHistory = new ArrayList<>();
    private SimpleDateFormat timeFormat = new SimpleDateFormat("HH:mm", Locale.getDefault());

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_main);

        chatDisplay = findViewById(R.id.chatDisplay);
        scrollView = findViewById(R.id.scrollView);
        inputField = findViewById(R.id.inputField);
        sendButton = findViewById(R.id.sendButton);
        statusText = findViewById(R.id.statusText);

        chatDisplay.setMovementMethod(new ScrollingMovementMethod());
        handler = new Handler(Looper.getMainLooper());

        // Create sovereign directory
        createSovereignDir();

        // Check permissions
        checkPermissions();

        // Set click listener
        sendButton.setOnClickListener(v -> sendMessage());

        // Set keyboard action
        inputField.setOnEditorActionListener((v, actionId, event) -> {
            if (actionId == EditorInfo.IME_ACTION_SEND) {
                sendMessage();
                return true;
            }
            return false;
        });

        // Welcome message
        addMessage("🤖", "Halo bro! Gue SOVEREIGN v2.5.\n\nKetik pesan atau command, gue akan proses.\n\nContoh:\n• Bersihin storage\n• Cek battery\n• Lihat proses\n• Health check", false);

        // Start monitoring agent status
        startStatusMonitor();
    }

    private void createSovereignDir() {
        File dir = new File(SOVEREIGN_DIR);
        if (!dir.exists()) {
            dir.mkdirs();
        }
    }

    private void checkPermissions() {
        if (ContextCompat.checkSelfPermission(this, Manifest.permission.WRITE_EXTERNAL_STORAGE)
                != PackageManager.PERMISSION_GRANTED) {
            ActivityCompat.requestPermissions(this,
                    new String[]{
                            Manifest.permission.WRITE_EXTERNAL_STORAGE,
                            Manifest.permission.READ_EXTERNAL_STORAGE
                    }, PERMISSION_REQUEST_CODE);
        }
    }

    private void sendMessage() {
        String message = inputField.getText().toString().trim();
        if (message.isEmpty()) return;

        // Add user message to chat
        addMessage("👤", message, true);
        inputField.setText("");

        // Disable input while processing
        setProcessing(true);

        // Write to input file
        writeToFile(INPUT_FILE, message);

        // Show processing status
        addMessage("🤖", "⏳ Processing...", false);

        // Start monitoring for response
        monitorAgentResponse();
    }

    private void monitorAgentResponse() {
        final int[] attempts = {0};
        final int maxAttempts = 60; // 60 seconds max

        Runnable checker = new Runnable() {
            @Override
            public void run() {
                attempts[0]++;

                // Check if output file exists and has new content
                String response = readFromFile(OUTPUT_FILE);
                if (response != null && !response.isEmpty()) {
                    // Remove processing message
                    removeLastMessage();

                    // Add agent response
                    addMessage("🤖", response, false);

                    // Enable input
                    setProcessing(false);

                    // Clear output file
                    writeToFile(OUTPUT_FILE, "");

                    // Save history
                    saveHistory();
                } else if (attempts[0] < maxAttempts) {
                    // Continue monitoring
                    handler.postDelayed(this, 1000);
                } else {
                    // Timeout
                    removeLastMessage();
                    addMessage("🤖", "⚠️ Timeout! Agent tidak merespon dalam 60 detik.\n\nPastikan Termux running dan agent aktif.", false);
                    setProcessing(false);
                }
            }
        };

        handler.postDelayed(checker, 1000);
    }

    private void addMessage(String sender, String message, boolean isUser) {
        String time = timeFormat.format(new Date());
        String formattedMessage = "\n" + sender + " [" + time + "]\n" + message + "\n";
        chatDisplay.append(formattedMessage);

        // Save to history
        chatHistory.add(new ChatMessage(sender, message, time));

        // Scroll to bottom
        scrollView.post(() -> scrollView.fullScroll(View.FOCUS_DOWN));
    }

    private void removeLastMessage() {
        String text = chatDisplay.getText().toString();
        // Find the last "🤖" and remove from there
        int lastBotIndex = text.lastIndexOf("\n🤖");
        if (lastBotIndex > 0) {
            chatDisplay.setText(text.substring(0, lastBotIndex));
        }
    }

    private void setProcessing(boolean processing) {
        inputField.setEnabled(!processing);
        sendButton.setEnabled(!processing);
        statusText.setText(processing ? "⏳ Agent processing..." : "✅ Ready");
        statusText.setTextColor(processing ?
                getResources().getColor(android.R.color.holo_orange_dark) :
                getResources().getColor(android.R.color.holo_green_dark));
    }

